// src/pages/LoginPage.jsx
import { useState } from 'react'
import { Link, useNavigate, Navigate } from 'react-router-dom'
import { Eye, EyeOff } from 'lucide-react'
import { useAuth } from '../context/AuthContext.jsx'

export default function LoginPage() {
  const { login, isAuthenticated } = useAuth()
  const navigate = useNavigate()

  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [showPassword, setShowPassword] = useState(false)
  const [error, setError] = useState('')
  const [loading, setLoading] = useState(false)

  // Redirige si déjà connecté
  if (isAuthenticated) {
    return <Navigate to="/" replace />
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setError('')

    if (!email.trim() || !password) {
      setError('Veuillez remplir tous les champs.')
      return
    }

    setLoading(true)
    try {
      const user = await login({ email: email.trim(), password })
      navigate(user?.role === 'admin' ? '/admin' : '/', { replace: true })
    } catch (err) {
      const message =
        err?.response?.data?.message ||
        err?.message ||
        'Email ou mot de passe incorrect.'
      setError(message)
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-[80vh] flex items-center justify-center px-4 py-12">
      <div className="w-full max-w-sm">
        {/* Titre */}
        <div className="text-center mb-8">
          <h1 className="font-serif text-3xl text-charcoal mb-2">Connexion</h1>
          <p className="text-sm text-gray-medium">
            Connectez-vous pour accéder à votre compte
          </p>
        </div>

        {/* Erreur */}
        {error && (
          <div className="mb-6 p-3 bg-red-50 border border-red-200 rounded-lg text-sm text-error text-center">
            {error}
          </div>
        )}

        {/* Formulaire */}
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label
              htmlFor="email"
              className="block text-xs text-gray-medium uppercase tracking-wider mb-1.5"
            >
              Email
            </label>
            <input
              id="email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="votre@email.com"
              autoComplete="email"
              className="w-full bg-cream-dark border border-transparent focus:border-terracotta/30 rounded-xl px-4 py-3 text-sm text-charcoal placeholder:text-gray-light outline-none transition-colors"
            />
          </div>

          <div>
            <label
              htmlFor="password"
              className="block text-xs text-gray-medium uppercase tracking-wider mb-1.5"
            >
              Mot de passe
            </label>
            <div className="relative">
              <input
                id="password"
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
                autoComplete="current-password"
                className="w-full bg-cream-dark border border-transparent focus:border-terracotta/30 rounded-xl pl-4 pr-10 py-3 text-sm text-charcoal placeholder:text-gray-light outline-none transition-colors"
              />
              <button
                type="button"
                onClick={() => setShowPassword((p) => !p)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-light hover:text-gray-medium transition-colors"
                aria-label={showPassword ? 'Masquer le mot de passe' : 'Afficher le mot de passe'}
              >
                {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-black-solid hover:bg-charcoal text-white text-sm font-medium px-6 py-3 rounded-full transition-colors disabled:opacity-60 disabled:cursor-not-allowed"
          >
            {loading ? 'Connexion...' : 'Se connecter'}
          </button>
        </form>

        {/* Lien register */}
        <p className="text-center text-sm text-gray-medium mt-6">
          Pas encore de compte ?{' '}
          <Link
            to="/register"
            className="text-terracotta hover:text-terracotta-hover font-medium transition-colors"
          >
            Créer un compte
          </Link>
        </p>
      </div>
    </div>
  )
}

// src/pages/DashboardPage.jsx
import { useState, useEffect } from 'react'
import { Link } from 'react-router-dom'
import { Plus, Pencil, Trash2, Archive } from 'lucide-react'
import ProductCard from '../components/ProductCard.jsx'
import { getProducts } from '../api/products.js'

export default function DashboardPage() {
  const [products, setProducts] = useState([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    getProducts({ per_page: 50 }).then((res) => {
      setProducts(res.data.data || [])
    }).catch(() => setProducts([]))
    .finally(() => setLoading(false))
  }, [])

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* En-tête */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-6">
        <div>
          <h1 className="font-serif text-2xl md:text-3xl text-charcoal">Tableau de bord</h1>
          <p className="text-sm text-gray-medium mt-1">
            {products.length} article{products.length !== 1 ? 's' : ''} publié{products.length !== 1 ? 's' : ''}
          </p>
        </div>
        <Link
          to="/publish"
          className="inline-flex items-center gap-2 bg-terracotta hover:bg-terracotta-hover text-white text-sm font-medium px-5 py-2.5 rounded-full transition-colors"
        >
          <Plus size={18} />
          Ajouter un article
        </Link>
      </div>

      {/* Grille */}
      {loading ? (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4">
          {Array.from({ length: 4 }, (_, i) => (
            <div key={i} className="animate-pulse">
              <div className="aspect-[4/5] bg-cream-dark rounded-lg" />
              <div className="p-3 space-y-2">
                <div className="h-4 bg-cream-dark rounded w-3/4" />
                <div className="h-3 bg-cream-dark rounded w-1/2" />
              </div>
            </div>
          ))}
        </div>
      ) : products.length > 0 ? (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4">
          {products.map((p) => (
            <DashboardProductCard key={p.id} product={p} />
          ))}
        </div>
      ) : (
        <div className="text-center py-20">
          <p className="text-lg font-medium text-charcoal mb-2">
            Vous n&rsquo;avez pas encore publié d&rsquo;article.
          </p>
          <Link to="/publish" className="text-sm text-terracotta hover:text-terracotta-hover font-medium">
            + Publier mon premier article
          </Link>
        </div>
      )}
    </div>
  )
}

function DashboardProductCard({ product }) {
  const [menuOpen, setMenuOpen] = useState(false)

  return (
    <div className="relative group">
      <ProductCard product={product} showFavorite={false} />

      {/* Actions au survol */}
      <div className="absolute top-2 right-2 flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
        <button
          onClick={(e) => { e.preventDefault(); e.stopPropagation(); setMenuOpen(!menuOpen) }}
          className="w-8 h-8 rounded-full bg-white shadow flex items-center justify-center text-gray-medium hover:text-charcoal transition-colors"
          title="Actions"
        >
          <Pencil size={14} />
        </button>
      </div>

      {/* Status badge */}
      <span className="absolute top-2 left-2 text-[10px] bg-cream-dark text-charcoal px-2 py-0.5 rounded-full">
        Publié
      </span>

      {/* Menu actions */}
      {menuOpen && (
        <div className="absolute top-10 right-2 bg-white shadow-lg rounded-lg py-1 z-10 min-w-[140px]" onMouseLeave={() => setMenuOpen(false)}>
          <button className="w-full text-left px-3 py-2 text-xs text-gray-medium hover:text-charcoal hover:bg-cream-dark flex items-center gap-2">
            <Pencil size={12} /> Modifier
          </button>
          <button className="w-full text-left px-3 py-2 text-xs text-gray-medium hover:text-charcoal hover:bg-cream-dark flex items-center gap-2">
            <Archive size={12} /> Marquer comme vendu
          </button>
          <button className="w-full text-left px-3 py-2 text-xs text-error hover:bg-red-50 flex items-center gap-2">
            <Trash2 size={12} /> Supprimer
          </button>
        </div>
      )}
    </div>
  )
}

// src/pages/FavoritesPage.jsx
import { useState, useEffect } from 'react'
import { Link } from 'react-router-dom'
import { Heart } from 'lucide-react'
import ProductCard from '../components/ProductCard.jsx'
import { getProducts } from '../api/products.js'

export default function FavoritesPage() {
  const [favorites, setFavorites] = useState([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    // En mock : on filtre les produits avec is_favorite=true
    getProducts({ per_page: 50 }).then((res) => {
      const favs = (res.data.data || []).filter((p) => p.is_favorite)
      setFavorites(favs)
    }).catch(() => setFavorites([]))
    .finally(() => setLoading(false))
  }, [])

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <h1 className="font-serif text-2xl md:text-3xl text-charcoal mb-2">Mes favoris</h1>

      {loading ? (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4 mt-6">
          {Array.from({ length: 4 }, (_, i) => (
            <div key={i} className="animate-pulse">
              <div className="aspect-[4/5] bg-cream-dark rounded-lg" />
              <div className="p-3 space-y-2">
                <div className="h-4 bg-cream-dark rounded w-3/4" />
                <div className="h-3 bg-cream-dark rounded w-1/2" />
              </div>
            </div>
          ))}
        </div>
      ) : favorites.length > 0 ? (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4 mt-6">
          {favorites.map((p) => (
            <ProductCard key={p.id} product={p} />
          ))}
        </div>
      ) : (
        <div className="text-center py-20">
          <div className="w-16 h-16 rounded-full bg-cream-dark flex items-center justify-center mx-auto mb-4">
            <Heart size={28} className="text-gray-light" />
          </div>
          <p className="text-lg font-medium text-charcoal mb-2">
            Vos articles favoris apparaîtront ici.
          </p>
          <p className="text-sm text-gray-medium mb-4">
            Ajoutez des articles à vos favoris pour les retrouver facilement.
          </p>
          <Link
            to="/search"
            className="inline-flex items-center gap-1 text-sm text-terracotta hover:text-terracotta-hover font-medium transition-colors"
          >
            Explorer les articles →
          </Link>
        </div>
      )}
    </div>
  )
}

// src/components/ProductCard.jsx
import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { Heart } from 'lucide-react'
import { useAuth } from '../context/AuthContext.jsx'
import { toggleFavorite } from '../api/favorites.js'

/** Formate un prix en FCFA avec séparateur de milliers */
function formatPrice(price) {
  return new Intl.NumberFormat('fr-FR', {
    style: 'decimal',
    maximumFractionDigits: 0,
  }).format(price) + ' FCFA'
}

/** Calcule le pourcentage de réduction */
function discountPercent(original, current) {
  if (!original || original <= current) return null
  return Math.round(((original - current) / original) * 100)
}

/** Labels d'état */
const CONDITION_LABELS = {
  new: 'Neuf',
  like_new: 'Comme neuf',
  very_good: 'Très bon état',
  good: 'Bon état',
  satisfactory: 'État satisfaisant',
}

/** Bouton favori avec toggle */
function FavoriteButton({ productId, initial }) {
  const [isFav, setIsFav] = useState(initial)
  const { isAuthenticated } = useAuth()
  const navigate = useNavigate()

  const toggle = (e) => {
    e.preventDefault()
    e.stopPropagation()
    if (!isAuthenticated) {
      navigate('/login')
      return
    }
    setIsFav((prev) => !prev)
    toggleFavorite(productId).catch(() => setIsFav((prev) => !prev))
  }

  return (
    <button
      onClick={toggle}
      className="absolute bottom-2 right-2 p-1.5 rounded-full bg-white/80 backdrop-blur-sm text-gray-medium hover:text-terracotta transition-colors"
      aria-label={isFav ? 'Retirer des favoris' : 'Ajouter aux favoris'}
    >
      <Heart
        size={16}
        fill={isFav ? '#D98C4A' : 'none'}
        stroke={isFav ? '#D98C4A' : 'currentColor'}
      />
    </button>
  )
}

export default function ProductCard({ product, showFavorite = true }) {
  const {
    id,
    title,
    brand,
    size,
    condition,
    price,
    original_price,
    images,
    is_favorite,
  } = product

  const discount = discountPercent(original_price, price)
  const hasImage = images && images.length > 0
  const isNew = condition === 'new'

  return (
    <Link
      to={`/product/${id}`}
      className="group block rounded-lg overflow-hidden bg-cream transition-shadow hover:shadow-md"
    >
      {/* Image */}
      <div className="relative aspect-[4/5] bg-cream-dark overflow-hidden">
        {hasImage ? (
          <img
            src={images[0]}
            alt={title}
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
          />
        ) : (
          <div className="w-full h-full flex items-center justify-center">
            <span className="text-gray-light text-xs">Image indisponible</span>
          </div>
        )}

        {/* Badges */}
        <div className="absolute top-2 left-2 flex flex-col gap-1.5">
          {isNew && (
            <span className="inline-block bg-black-solid text-white text-[10px] font-medium px-2 py-0.5 rounded-full">
              Neuf
            </span>
          )}
        </div>

        {discount && (
          <span className="absolute top-2 right-2 inline-block bg-terracotta-light text-terracotta text-[10px] font-semibold px-2 py-0.5 rounded-full">
            -{discount}%
          </span>
        )}

        {/* Favoris (optionnel) */}
        {showFavorite && <FavoriteButton productId={id} initial={is_favorite} />}
      </div>

      {/* Infos */}
      <div className="p-3">
        <h3 className="text-sm font-medium text-charcoal line-clamp-2 mb-1">
          {title}
        </h3>
        <p className="text-xs text-gray-light mb-2">
          {brand}{size ? ` · ${size}` : ''}
        </p>
        <div className="flex items-baseline gap-2">
          <span className="text-sm font-semibold text-charcoal">
            {formatPrice(price)}
          </span>
          {original_price && original_price > price && (
            <span className="text-xs text-gray-light line-through">
              {formatPrice(original_price)}
            </span>
          )}
        </div>
      </div>
    </Link>
  )
}

