import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Search } from 'lucide-react'

export default function SearchBar({ className = '', onSearch }) {
  const [query, setQuery] = useState('')
  const navigate = useNavigate()

  const handleSubmit = (e) => {
    e.preventDefault()
    const trimmed = query.trim()
    if (!trimmed) return
    if (onSearch) {
      onSearch(trimmed)
    } else {
      navigate(`/search?q=${encodeURIComponent(trimmed)}`)
    }
  }

  return (
    <form
      onSubmit={handleSubmit}
      className={`relative flex-1 max-w-md mx-4 ${className}`}
    >
      <input
        type="text"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        placeholder="Rechercher un article, une marque, une couleur..."
        className="w-full bg-cream-dark border border-transparent focus:border-terracotta/30 rounded-full pl-10 pr-4 py-2 text-sm text-charcoal placeholder:text-gray-light outline-none transition-colors"
      />
      <button
        type="submit"
        className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-light hover:text-terracotta transition-colors"
        aria-label="Rechercher"
      >
        <Search size={16} />
      </button>
    </form>
  )
}

// src/components/ImageGallery.jsx
import { useState } from 'react'
import { ChevronLeft, ChevronRight } from 'lucide-react'

export default function ImageGallery({ images = [] }) {
  const [current, setCurrent] = useState(0)

  const hasImages = images.length > 0
  const total = hasImages ? images.length : 1

  const prev = () => setCurrent((c) => (c === 0 ? total - 1 : c - 1))
  const next = () => setCurrent((c) => (c === total - 1 ? 0 : c + 1))

  return (
    <div>
      {/* Vue principale */}
      <div className="relative aspect-[4/5] bg-cream-dark rounded-lg overflow-hidden mb-3">
        {hasImages ? (
          <>
            <img
              src={images[current]}
              alt={`Photo ${current + 1}`}
              className="w-full h-full object-cover"
            />

            {/* Flèches */}
            {total > 1 && (
              <>
                <button
                  onClick={prev}
                  className="absolute left-2 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full bg-white/80 backdrop-blur-sm flex items-center justify-center text-charcoal hover:bg-white transition-colors"
                  aria-label="Image précédente"
                >
                  <ChevronLeft size={18} />
                </button>
                <button
                  onClick={next}
                  className="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 rounded-full bg-white/80 backdrop-blur-sm flex items-center justify-center text-charcoal hover:bg-white transition-colors"
                  aria-label="Image suivante"
                >
                  <ChevronRight size={18} />
                </button>
              </>
            )}

            {/* Indicateurs */}
            {total > 1 && (
              <div className="absolute bottom-3 left-1/2 -translate-x-1/2 flex gap-1.5">
                {Array.from({ length: total }, (_, i) => (
                  <button
                    key={i}
                    onClick={() => setCurrent(i)}
                    className={`w-1.5 h-1.5 rounded-full transition-colors ${
                      i === current ? 'bg-white' : 'bg-white/40'
                    }`}
                    aria-label={`Aller à l'image ${i + 1}`}
                  />
                ))}
              </div>
            )}
          </>
        ) : (
          <div className="w-full h-full flex items-center justify-center">
            <span className="text-gray-light text-sm">Image indisponible</span>
          </div>
        )}
      </div>

      {/* Miniatures desktop */}
      {hasImages && total > 1 && (
        <div className="hidden md:flex gap-2">
          {images.map((img, i) => (
            <button
              key={i}
              onClick={() => setCurrent(i)}
              className={`w-16 h-20 rounded-md overflow-hidden border-2 transition-colors ${
                i === current ? 'border-terracotta' : 'border-transparent hover:border-gray-light'
              }`}
            >
              <img src={img} alt="" className="w-full h-full object-cover" />
            </button>
          ))}
        </div>
      )}
    </div>
  )
}

