// src/components/BottomNav.jsx
import { Link, useLocation } from 'react-router-dom'
import { Home, Search, PlusCircle, Heart, User } from 'lucide-react'
import { useAuth } from '../context/AuthContext.jsx'

const NAV_ITEMS = [
  { to: '/', icon: Home, label: 'Accueil' },
  { to: '/search', icon: Search, label: 'Recherche' },
  { to: '/publish', icon: PlusCircle, label: 'Vendre', highlight: true },
  { to: '/favorites', icon: Heart, label: 'Favoris' },
]

export default function BottomNav() {
  const location = useLocation()
  const { isAuthenticated, user } = useAuth()

  const isActive = (path) => {
    if (path === '/') return location.pathname === '/'
    return location.pathname.startsWith(path)
  }

  return (
    <nav className="md:hidden fixed bottom-0 left-0 right-0 z-50 bg-cream border-t border-cream-dark/50 safe-area-bottom">
      <div className="flex items-center justify-around h-16 px-2">
        {NAV_ITEMS.map(({ to, icon: Icon, label, highlight }) => {
          const active = isActive(to)
          return (
            <Link
              key={to}
              to={to}
              className={`flex flex-col items-center justify-center gap-0.5 min-w-0 px-1 py-1 transition-colors ${
                highlight
                  ? 'text-terracotta font-medium'
                  : active
                    ? 'text-terracotta'
                    : 'text-gray-light hover:text-gray-medium'
              }`}
            >
              <Icon
                size={highlight ? 26 : 22}
                strokeWidth={active || highlight ? 2.5 : 2}
              />
              <span className="text-[10px] leading-tight whitespace-nowrap">
                {label}
              </span>
            </Link>
          )
        })}

        {/* Profil (dernier item, conditionnel) */}
        <Link
          to={isAuthenticated ? (user?.role === 'admin' ? '/admin' : '/profile') : '/login'}
          className={`flex flex-col items-center justify-center gap-0.5 min-w-0 px-1 py-1 transition-colors ${
            isActive('/profile') || isActive('/admin') ? 'text-terracotta' : 'text-gray-light hover:text-gray-medium'
          }`}
        >
          <User size={22} strokeWidth={isActive('/profile') ? 2.5 : 2} />
          <span className="text-[10px] leading-tight whitespace-nowrap">
            Profil
          </span>
        </Link>
      </div>
    </nav>
  )
}

// src/components/SearchBar.jsx
import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Search } from 'lucide-react'

export default function SearchBar({ className = '', onSearch }) {
  const [query, setQuery] = useState('')
  const navigate = useNavigate()

  const handleSubmit = (e) => {
    e.preventDefault()
    const trimmed = query.trim()
    if (!trimmed) return
    if (onSearch) {
      onSearch(trimmed)
    } else {
      navigate(`/search?q=${encodeURIComponent(trimmed)}`)
    }
  }

  return (
    <form
      onSubmit={handleSubmit}
      className={`relative flex-1 max-w-md mx-4 ${className}`}
    >
      <input
        type="text"
        value={query}
        onChange={(e) => setQuery(e.target.value)}
        placeholder="Rechercher un article, une marque, une couleur..."
        className="w-full bg-cream-dark border border-transparent focus:border-terracotta/30 rounded-full pl-10 pr-4 py-2 text-sm text-charcoal placeholder:text-gray-light outline-none transition-colors"
      />
      <button
        type="submit"
        className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-light hover:text-terracotta transition-colors"
        aria-label="Rechercher"
      >
        <Search size={16} />
      </button>
    </form>
  )
}

// src/components/MegaMenu.jsx
import { useState, useEffect, useRef } from 'react'
import { Link } from 'react-router-dom'
import { ChevronDown } from 'lucide-react'
import { getCategories } from '../api/categories.js'

export default function MegaMenu() {
  const [categories, setCategories] = useState([])
  const [activeCategory, setActiveCategory] = useState(null)
  const [loading, setLoading] = useState(true)
  const menuRef = useRef(null)
  const hoverTimeout = useRef(null)

  useEffect(() => {
    getCategories()
      .then((res) => setCategories(res.data.data))
      .catch(() => {})
      .finally(() => setLoading(false))
  }, [])

  // Ferme le mega-menu au clic extérieur
  useEffect(() => {
    if (!activeCategory) return
    const handleClick = (e) => {
      if (menuRef.current && !menuRef.current.contains(e.target)) {
        setActiveCategory(null)
      }
    }
    document.addEventListener('mousedown', handleClick)
    return () => document.removeEventListener('mousedown', handleClick)
  }, [activeCategory])

  const handleMouseEnter = (slug) => {
    clearTimeout(hoverTimeout.current)
    setActiveCategory(slug)
  }

  const handleMouseLeave = () => {
    hoverTimeout.current = setTimeout(() => setActiveCategory(null), 200)
  }

  const activeCategoryData = categories.find((c) => c.slug === activeCategory)

  if (loading) return null

  return (
    <div ref={menuRef} className="border-t border-cream-dark/50 bg-cream">
      {/* Nav horizontale */}
      <nav className="max-w-7xl mx-auto px-4">
        <ul className="flex items-center gap-1 overflow-x-auto scrollbar-hide">
          {categories.map((cat) => (
            <li key={cat.slug}>
              <button
                onClick={() =>
                  setActiveCategory(activeCategory === cat.slug ? null : cat.slug)
                }
                onMouseEnter={() => handleMouseEnter(cat.slug)}
                onMouseLeave={handleMouseLeave}
                className={`flex items-center gap-1.5 px-3 py-3 text-sm whitespace-nowrap transition-colors border-b-2 ${
                  activeCategory === cat.slug
                    ? 'border-terracotta text-terracotta font-medium'
                    : 'border-transparent text-gray-medium hover:text-charcoal'
                }`}
              >
                {cat.name}
                <ChevronDown
                  size={14}
                  className={`transition-transform ${
                    activeCategory === cat.slug ? 'rotate-180' : ''
                  }`}
                />
              </button>
            </li>
          ))}
        </ul>
      </nav>

      {/* Mega-menu dropdown */}
      {activeCategory && activeCategoryData && (
        <div
          className="absolute left-0 right-0 bg-cream border-t border-cream-dark/50 shadow-sm z-40"
          onMouseEnter={() => clearTimeout(hoverTimeout.current)}
          onMouseLeave={handleMouseLeave}
        >
          <div className="max-w-7xl mx-auto px-4 py-6">
            <div className="grid grid-cols-2 md:grid-cols-4 gap-8">
              {/* Lien "Tout voir" */}
              <div>
                <Link
                  to={`/category/${activeCategoryData.slug}`}
                  onClick={() => setActiveCategory(null)}
                  className="text-terracotta hover:text-terracotta-hover font-medium text-sm transition-colors"
                >
                  Tout voir dans {activeCategoryData.name} →
                </Link>
              </div>

              {/* Colonnes de sous-catégories */}
              {activeCategoryData.subcategories.map((sub) => (
                <div key={sub.name}>
                  <h4 className="text-xs text-gray-light font-medium uppercase tracking-wider mb-3">
                    {sub.name}
                  </h4>
                  <ul className="space-y-2">
                    {sub.children.map((child) => (
                      <li key={child}>
                        <Link
                          to={`/category/${activeCategoryData.slug}?subcategory=${encodeURIComponent(child)}`}
                          onClick={() => setActiveCategory(null)}
                          className="text-sm text-charcoal hover:text-terracotta transition-colors"
                        >
                          {child}
                        </Link>
                      </li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

// src/components/FilterBar.jsx
import { useState, useEffect } from 'react'
import { getCategories } from '../api/categories.js'

const CONDITIONS = [
  { value: 'new', label: 'Neuf avec étiquette' },
  { value: 'like_new', label: 'Comme neuf' },
  { value: 'very_good', label: 'Très bon état' },
  { value: 'good', label: 'Bon état' },
  { value: 'satisfactory', label: 'État satisfaisant' },
]

export default function FilterBar({
  filters,
  onChange,
  className = '',
}) {
  const [categories, setCategories] = useState([])
  const selectedCategory = categories.find((c) => c.slug === filters.category)

  useEffect(() => {
    getCategories().then((res) => setCategories(res.data.data)).catch(() => {})
  }, [])

  const update = (key, value) => onChange({ ...filters, [key]: value })
  const toggleCondition = (val) => {
    const current = filters.conditions || []
    const next = current.includes(val)
      ? current.filter((c) => c !== val)
      : [...current, val]
    update('conditions', next)
  }

  const formatPrice = (p) =>
    new Intl.NumberFormat('fr-FR').format(p) + ' FCFA'

  return (
    <aside className={`bg-cream ${className}`}>
      <div className="space-y-6">
        {/* CATÉGORIE */}
        <FilterSection title="Catégorie">
          <button
            onClick={() => update('category', '')}
            className={`block w-full text-left text-sm py-1.5 transition-colors ${
              !filters.category ? 'text-terracotta font-medium' : 'text-gray-medium hover:text-charcoal'
            }`}
          >
            Toutes
          </button>
          {categories.map((cat) => (
            <button
              key={cat.slug}
              onClick={() => update('category', cat.slug)}
              className={`block w-full text-left text-sm py-1.5 transition-colors ${
                filters.category === cat.slug
                  ? 'text-terracotta font-medium'
                  : 'text-gray-medium hover:text-charcoal'
              }`}
            >
              {cat.name}
            </button>
          ))}
        </FilterSection>

        {/* SOUS-CATÉGORIE */}
        {selectedCategory && selectedCategory.subcategories?.length > 0 && (
          <FilterSection title="Sous-catégorie">
            <button
              onClick={() => update('subcategory', '')}
              className={`block w-full text-left text-sm py-1.5 transition-colors ${
                !filters.subcategory ? 'text-terracotta font-medium' : 'text-gray-medium hover:text-charcoal'
              }`}
            >
              Toutes
            </button>
            {selectedCategory.subcategories.flatMap((sub) =>
              sub.children.map((child) => (
                <button
                  key={child}
                  onClick={() => update('subcategory', child)}
                  className={`block w-full text-left text-sm py-1.5 transition-colors ${
                    filters.subcategory === child
                      ? 'text-terracotta font-medium'
                      : 'text-gray-medium hover:text-charcoal'
                  }`}
                >
                  {child}
                </button>
              ))
            )}
          </FilterSection>
        )}

        {/* ÉTAT */}
        <FilterSection title="État">
          {CONDITIONS.map((cond) => {
            const active = (filters.conditions || []).includes(cond.value)
            return (
              <button
                key={cond.value}
                onClick={() => toggleCondition(cond.value)}
                className={`flex items-center gap-2 w-full text-left text-sm py-1.5 transition-colors ${
                  active ? 'text-terracotta font-medium' : 'text-gray-medium hover:text-charcoal'
                }`}
              >
                <span
                  className={`w-4 h-4 rounded border-2 flex items-center justify-center shrink-0 transition-colors ${
                    active
                      ? 'border-terracotta bg-terracotta'
                      : 'border-gray-light'
                  }`}
                >
                  {active && (
                    <svg width="10" height="10" viewBox="0 0 10 10" fill="none">
                      <path d="M2 5l2 2 4-4" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                    </svg>
                  )}
                </span>
                {cond.label}
              </button>
            )
          })}
        </FilterSection>

        {/* PRIX MAX */}
        <FilterSection title="Prix max">
          <div className="space-y-2">
            <input
              type="range"
              min="500"
              max="200000"
              step="500"
              value={filters.maxPrice || 200000}
              onChange={(e) => update('maxPrice', Number(e.target.value))}
              className="w-full accent-terracotta h-1.5"
            />
            <div className="flex justify-between text-xs text-gray-light">
              <span>500 FCFA</span>
              <span className="text-terracotta font-medium">
                {formatPrice(filters.maxPrice || 200000)}
              </span>
              <span>200 000 FCFA</span>
            </div>
          </div>
        </FilterSection>
      </div>
    </aside>
  )
}

function FilterSection({ title, children }) {
  return (
    <div>
      <h4 className="text-xs text-gray-light uppercase tracking-wider mb-2 font-medium">
        {title}
      </h4>
      {children}
    </div>
  )
}

