@import "tailwindcss";

/* ── Design System: Yolanda ── */
@theme {
  /* Palette */
  --color-cream: #F7F4ED;
  --color-cream-dark: #EDE9E1;
  --color-terracotta: #D98C4A;
  --color-terracotta-light: #F5E6D3;
  --color-terracotta-hover: #C57A3A;
  --color-charcoal: #1A1A1A;
  --color-black-solid: #111111;
  --color-warm-gray: #EDE9E1;
  --color-gray-medium: #6B6B6B;
  --color-gray-light: #9CA3AF;
  --color-success: #16A34A;
  --color-error: #DC2626;

  /* Typographie */
  --font-serif: 'Playfair Display', Georgia, serif;
  --font-sans: 'Inter', system-ui, -apple-system, sans-serif;

  /* Border radius */
  --radius-pill: 9999px;
  --radius-card: 8px;
  --radius-btn: 9999px;
}

/* ── Base ── */
body {
  @apply bg-cream text-charcoal font-sans antialiased;
  margin: 0;
}

#root {
  @apply min-h-screen flex flex-col;
}

/* ── Scrollbar styling ── */
::-webkit-scrollbar {
  width: 6px;
}
::-webkit-scrollbar-track {
  @apply bg-cream;
}
::-webkit-scrollbar-thumb {
  @apply bg-gray-light rounded-full;
}

/* ── Utility: hide scrollbar for horizontal scrolls ── */
.scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
}
.scrollbar-hide::-webkit-scrollbar {
  display: none;
}

/* ── Safe-area padding for mobile bottom bars ── */
.pb-safe {
  padding-bottom: env(safe-area-inset-bottom, 0px);
}

